{
 "level": "A1–A2",
 "intro": "In this topic, you will learn the <strong>basic word order</strong> in English affirmative sentences: the S–V–O structure, the arrangement of adverbs of frequency and adverbials of time and place.",
 "rules": [
 {
 "label": "Basic structure",
 "color": "emerald",
 "text": "<strong>Subject + Verb + Object</strong> is the basis of an English sentence:",
 "example": "She reads books."
 },
 {
 "label": "Adverbs of frequency",
 "color": "blue",
 "text": "<strong>Always, often, sometimes, never</strong> stand before the main verb:",
 "example": "I always drink tea in the morning."
 },
 {
 "label": "Time and place",
 "color": "amber",
 "text": "<strong>Place + Time</strong> usually at the end of the sentence:",
 "example": "We play football in the park every Sunday."
 }
 ]
}

{
 "title": "1. Structure S–V–O (Subject–Verb–Object)",
 "intro": "The English affirmative sentence is built according to the scheme:",
 "items": [
 {
 "label": "S — Subject",
 "title": "Subject",
 "subtitle": "Who or what performs the action (I, you, she, Tom, the dog)"
 },
 {
 "label": "V — Verb",
 "title": "Verb",
 "subtitle": "Action or state (read, eat, is, have)"
 },
 {
 "label": "O — Object",
 "title": "Object",
 "subtitle": "To whom/what is the action directed (book, coffee, him)"
 }
 ]
}

{
 "title": "2. Adverbs of Frequency",
 "sections": [
 {
 "label": "Before the main verb",
 "color": "emerald",
 "description": "The adverbs <strong>always, usually, often, sometimes, rarely, never</strong> are placed <strong>before</strong> the main verb.",
 "examples": [
 {
 "en": "She always eats breakfast.",
 "ua": "She always eats breakfast."
 },
 {
 "en": "I often go to the gym.",
 "ua": "I often go to the gym."
 },
 {
 "en": "They never drink coffee.",
 "ua": "They never drink coffee."
 }
 ]
 },
 {
 "label": "After the verb TO BE",
 "color": "sky",
 "description": "If the verb <strong>to be</strong> (am, is, are, was, were) is in the sentence the adverb of frequency is placed <strong>after</strong> him.",
 "examples": [
 {
 "en": "He is always late.",
 "ua": "He is always late."
 },
 {
 "en": "She is usually happy.",
 "ua": "She is usually happy."
 },
 {
 "en": "They are never bored.",
 "ua": "They are never bored."
 }
 ]
 },
 {
 "label": "Sometimes / Usually at the beginning",
 "color": "amber",
 "description": "Some adverbs (<strong>sometimes, usually, often</strong>) can stand at the beginning of a sentence for emphasis.",
 "examples": [
 {
 "en": "Sometimes I read before bed.",
 "ua": "Sometimes I read before bed."
 },
 {
 "en": "Usually we have dinner at 7.",
 "ua": "Usually we have dinner at 7."
 }
 ],
 "note": "<strong>Always</strong> and <strong>never</strong> are rarely put at the beginning of a sentence."
 }
 ]
}

{
 "title": "3. Time Adverbials)",
 "sections": [
 {
 "label": "At the end of the sentence",
 "color": "emerald",
 "description": "Time adverbials (<strong>yesterday, every day, at 7 o'clock, last week</strong>) are usually <strong>at the end</strong> of the sentence.",
 "examples": [
 {
 "en": "I wake up at 6 o'clock.",
 "ua": "I wake up at 6 o'clock."
 },
 {
 "en": "She studies English every day.",
 "ua": "She studies English every day."
 },
 {
 "en": "We went to the cinema last night.",
 "ua": "We went to the cinema last night."
 }
 ]
 },
 {
 "label": "At the beginning of the sentence",
 "color": "sky",
 "description": "For emphasis, time adverbials can go <strong>at the beginning</strong>.",
 "examples": [
 {
 "en": "Yesterday, I met an old friend.",
 "ua": "Yesterday, I met an old friend."
 },
 {
 "en": "Every morning, she jogs in the park.",
 "ua": "Every morning, she jogs in the park."
 }
 ]
 }
 ]
}

{
 "title": "4. Place Adverbials",
 "sections": [
 {
 "label": "After the verb / adverb",
 "color": "emerald",
 "description": "Place Adverbials (<strong>at school, in the park, at home</strong>) are placed <strong>after the verb</strong> or <strong>adverb</strong>.",
 "examples": [
 {
 "en": "He works at the office.",
 "ua": "He works at the office."
 },
 {
 "en": "She reads books in her room.",
 "ua": "She reads books in her room."
 }
 ]
 },
 {
 "label": "Place before Time",
 "color": "sky",
 "description": "If there is both place and time, the order is: Time</strong>.",
 "examples": [
 {
 "en": "We eat dinner at home on Sundays.",
 "ua": "We eat dinner at home on Sundays."
 },
 {
 "en": "The children play in the park every afternoon.",
 "ua": "The children play in the park every afternoon."
 }
 ]
 }
 ]
}

{
 "title": "5. Complete sentence structure",
 "intro": "Complete order of elements in an affirmative sentence:",
 "rows": [
 {
 "en": "Subject",
 "ua": "Subject",
 "note": "She, Tom, They"
 },
 {
 "en": "Adverb of Frequency",
 "ua": "Adverb of Frequency",
 "note": "always, often, never (before the main verb)"
 },
 {
 "en": "Verb",
 "ua": "Verb",
 "note": "reads, eats, plays"
 },
 {
 "en": "Object",
 "ua": "Object",
 "note": "books, coffee, football"
 },
 {
 "en": "Place",
 "ua": "Place",
 "note": "at school, in the park"
 },
 {
 "en": "Time",
 "ua": "Time",
 "note": "every day, yesterday, at 7 o'clock"
 }
 ],
 "warning": "📌 Formula: <strong>S + (Adv) + V + O + Place + Time</strong>"
}

{
 "title": "6. Typical mistakes of Ukrainian-speakers",
 "items": [
 {
 "label": "Error 1",
 "color": "rose",
 "title": "Change of S–V–O order by dropping the subject.",
 "wrong": "Reads she books every day.",
 "right": "​​​​ <span class=\"font-mono\">She reads books every day.</span>"
 },
 {
 "label": "Error 2",
 "color": "amber",
 "title": "Incorrect placement of adverb of frequency.",
 "wrong": "She reads always books.",
 "right": "​​​​​​​​ end."
 },
 {
 "label": "Mistake 3",
 "color": "sky",
 "title": "Putting time in the middle instead of at the end.",
 "wrong": "I go every day to school.",
 "right": "​​​​ <span class=\"font-mono\">I go to school every day.</span>"
 }
 ]
}

{
 "title": "7. Brief synopsis",
 "items": [
 "Basic structure: <strong>S + V + O</strong> (subject + verb + object).",
 "Adverbs of frequency (<em>always, often, never</em>) — <strong>before the main verb</strong> or <strong>after to be</strong>.",
 "Adverbials of time (<em>yesterday, every day</em>) - usually <strong>at the end</strong> of a sentence.",
 "Adverbials of place (<em>at home, in the park</em>) - after an adverb, <strong>before time</strong>. Formula: <strong>S + (Adv) + V + O + Place + Time</strong>.",
 "Formula: <strong>S + (Adv) + V + O + Place + Time</strong>."
 ]
}

{
 "title": "8. Practice",
 "select_title": "Exercise 1. Choose the correct option",
 "select_intro": "Choose the sentence with the correct word order.",
 "selects": [
 {
 "label": "a) She always drinks coffee. / b) Always she drinks coffee.",
 "prompt": "Which option is correct?"
 },
 {
 "label": "a) I go to work every day. / b) I every day go to work.",
 "prompt": "Which option is correct?"
 },
 {
 "label": "a) He in the office works. / b) He works in the office.",
 "prompt": "Which option is correct?"
 }
 ],
 "options": [
 "a",
 "b"
 ],
 "input_title": "Exercise 2. Arrange the words in the correct order",
 "input_intro": "Make sentences from the given words.",
 "inputs": [
 {
 "before": "(she / reads / books / often)",
 "after": "→"
 },
 {
 "before": "(every morning / I / breakfast / eat)",
 "after": "→"
 },
 {
 "before": "(at home / on Sundays / we / dinner / have)",
 "after": "→"
 }
 ],
 "rephrase_title": " Exercise 3. Correction errors",
 "rephrase_intro": "Find and correct the error in the word order.",
 "rephrase": [
 {
 "example_label": "Example:",
 "example_original": "Plays he football every day.",
 "example_target": "He plays football every day."
 },
 {
 "original": "1. She always reads books in the evening.",
 "placeholder": "Correct the word order"
 },
 {
 "original": "2. We go every week to the supermarket.",
 "placeholder": "Correct word order"
 }
 ]
}
